import { NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";
import { createAdminClient } from "@/lib/supabase/admin";

export async function POST(request: Request) {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  let body: { post_id: string; query: string };
  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON" }, { status: 400 });
  }

  const { post_id, query } = body;
  if (!post_id || !query) {
    return NextResponse.json({ error: "post_id and query are required" }, { status: 400 });
  }

  // Unsplash Source API — no key needed, returns a random relevant image
  const slug = query.trim().replace(/\s+/g, ",");
  const imageUrl = `https://source.unsplash.com/featured/1600x900/?${encodeURIComponent(slug)}`;

  // Fetch the image
  const imgRes = await fetch(imageUrl, { redirect: "follow" });
  if (!imgRes.ok) {
    return NextResponse.json({ error: "Failed to fetch image from Unsplash" }, { status: 502 });
  }

  const buffer = await imgRes.arrayBuffer();
  const contentType = imgRes.headers.get("content-type") ?? "image/jpeg";
  const ext = contentType.includes("png") ? "png" : "jpg";
  const path = `${post_id}/cover-${Date.now()}.${ext}`;

  // Upload to Supabase Storage
  const admin = createAdminClient();
  const { error: uploadError } = await admin.storage
    .from("covers")
    .upload(path, buffer, { contentType, upsert: true });

  if (uploadError) {
    return NextResponse.json({ error: uploadError.message }, { status: 500 });
  }

  // Save path on post
  const { error: updateError } = await admin
    .from("posts")
    .update({ cover_image_path: path })
    .eq("id", post_id);

  if (updateError) {
    return NextResponse.json({ error: updateError.message }, { status: 500 });
  }

  const { data: urlData } = admin.storage.from("covers").getPublicUrl(path);

  return NextResponse.json({ success: true, path, publicUrl: urlData.publicUrl });
}
